parameters.text:
=Modera este comentario:

Nombre: {{ $json.Nombre }}
Estrellas: {{ $json.Estrellas }}
Comentario: {{ $json.Comentario }}
SessionID: {{ $json.sessionId }}

parameters.jsCode:
const input = $input.first().json;

const data = input.output;

// Fecha con zona horaria española automática (verano e invierno)
const now = new Date();

const fechaFormateada = now.toLocaleString('es-ES', {
  timeZone: 'Europe/Madrid',
  day: '2-digit',
  month: '2-digit',
  year: 'numeric',
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit',
  hour12: false
}).replace(',', ' -');

return [{
  json: {
    decision: data.decision,
    nombre: data.nombre,
    estrellas: data.estrellas,
    comentario: data.comentario,
    motivo: data.motivo,
    "fecha y hora": fechaFormateada
  }
}];

const input = $input.first().json;

const now = new Date();

// Fecha legible para Telegram y Google Sheets
const fechaLegible = now.toLocaleString('es-ES', {
  timeZone: 'Europe/Madrid',
  day: '2-digit',
  month: '2-digit',
  year: 'numeric',
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit',
  hour12: false
}).replace(',', ' -');

// Fecha en formato ISO para Supabase
const fechaISO = now.toLocaleString('sv-SE', {
  timeZone: 'Europe/Madrid'
}).replace(' ', 'T');

return [{
  json: {
    decision: input.decision,
    nombre: input.nombre,
    estrellas: input.estrellas,
    comentario: input.comentario,
    motivo: input.motivo,
    "fecha y hora": fechaLegible,
    "fecha_iso": fechaISO
  }
}];

const items = $input.all();

for (const item of items) {
  const nombre = item.json.Nombre || 'anonimo';
  const ip = item.json.headers?.['x-real-ip'] || 'noip';

  item.json.sessionId = `${nombre}-${ip}`;
}

return items;

// Normaliza la solicitud de contacto y construye el HTML del correo.
// El texto se escapa para que nadie pueda inyectar markup en el email.
const b = $input.first().json.body ?? {};

const esc = (v, max) => String(v ?? '').trim().slice(0, max)
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;');

const oVacio = (s) => s || 'No indicado';

const emailRaw = String(b.email ?? '').trim().slice(0, 255);
const emailValido = /^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(emailRaw);

const nombre   = oVacio(esc(b.nombre, 100));
const email    = oVacio(esc(emailRaw, 255));
const telefono = oVacio(esc(b.telefono, 20));
const servicio = oVacio(esc(b.servicio, 100));
const mensaje  = oVacio(esc(b.mensaje, 2000)).replace(/\n/g, '<br>');

const fecha = new Date().toLocaleString('es-ES', {
  timeZone: 'Europe/Madrid',
  day: '2-digit', month: '2-digit', year: 'numeric',
  hour: '2-digit', minute: '2-digit', hour12: false
}).replace(',', ' -');

const html = `
<div style="font-family:Arial,Helvetica,sans-serif;max-width:600px;color:#2d2438">
  <h2 style="color:#6b4f8a;margin-bottom:4px">Nueva solicitud de cita</h2>
  <p style="color:#7a7a7a;margin-top:0;font-size:13px">Recibida el ${fecha}</p>
  <table cellpadding="8" cellspacing="0" style="border-collapse:collapse;width:100%;margin-top:16px">
    <tr style="background:#f6f2fa"><td><strong>Nombre</strong></td><td>${nombre}</td></tr>
    <tr><td><strong>Email</strong></td><td>${email}</td></tr>
    <tr style="background:#f6f2fa"><td><strong>Telefono</strong></td><td>${telefono}</td></tr>
    <tr><td><strong>Servicio</strong></td><td>${servicio}</td></tr>
  </table>
  <h3 style="color:#6b4f8a;margin-bottom:4px">Mensaje</h3>
  <div style="background:#f6f2fa;padding:14px;border-radius:8px;line-height:1.5">${mensaje}</div>
  <p style="margin-top:20px;font-size:13px;color:#7a7a7a">
    Responde directamente a este correo y tu respuesta llegara a la clienta.
  </p>
</div>`;

return [{ json: { nombre, email, telefono, servicio, mensaje, fecha, html, replyTo: emailValido ? emailRaw : '' } }];

